36: // LivezHandler returns an http.HandlerFunc that always responds 200 OK,
37: // indicating the process is alive and serving HTTP.
38: func LivezHandler() http.HandlerFunc {
39: 	return func(w http.ResponseWriter, r *http.Request) {
40: 		w.WriteHeader(http.StatusOK)
41: 		_, _ = w.Write([]byte("OK"))
42: 	}
43: }
44: 
45: // ReadyzHandler returns an http.HandlerFunc that responds 200 OK only
46: // when the HealthNotifier reports ready; otherwise 503 Service Unavailable.
47: func ReadyzHandler(h *HealthNotifier) http.HandlerFunc {
48: 	return func(w http.ResponseWriter, r *http.Request) {
49: 		if h != nil && h.IsReady() {
50: 			w.WriteHeader(http.StatusOK)
51: 			_, _ = w.Write([]byte("OK"))
52: 			return
53: 		}
54: 		w.WriteHeader(http.StatusServiceUnavailable)
55: 		_, _ = w.Write([]byte("not ready"))
56: 	}
57: }
